/**
 * Backtrace API types for frontend apps.
 * Base URL: NEXT_PUBLIC_API_URL (default http://localhost:8000)
 *
 * All authenticated requests must use credentials: 'include'.
 */

export type UserStatus = "pending_setup" | "active" | "suspended";

export type IncidentStatus = "open" | "closed";

export type IncidentListFilter = "open" | "closed" | "all";

export type MonitoringHealthStatus =
  | "healthy"
  | "stale"
  | "degraded"
  | "setup_required"
  | "pending"
  | "inactive";

export type LifecycleStatus = "complete" | "single_event" | "empty";

export type CorrelationMethod =
  | "request_id"
  | "trace_id"
  | "session_id"
  | "span_id_endpoint"
  | "endpoint_service"
  | "host_pod_container"
  | "log_stream"
  | "none";

export type CorrelationConfidence =
  | "exact_request_id"
  | "trace_correlated"
  | "request_shape_match"
  | "stream_fallback"
  | "partial"
  | "no_request_id";

export interface ApiError {
  detail: string | ApiErrorDetail;
}

export interface ApiErrorDetail {
  detail: string;
  missing_steps?: string[];
}

export interface AuthMeResponse {
  id: string;
  email: string;
  name: string | null;
  status: UserStatus;
  created_at: string;
  onboarding_complete: boolean;
}

export interface OnboardingSteps {
  aws_connection_saved: boolean;
  aws_connection_verified: boolean;
  detection_config_saved: boolean;
  monitoring_active: boolean;
}

export interface AwsConnection {
  aws_region: string;
  log_group_name: string;
  role_arn: string;
  connection_verified_at: string | null;
  last_connection_error: string | null;
  last_connection_test_at: string | null;
}

export interface DetectionConfig {
  error_filter_field: string;
  error_filter_values: string[];
  lifecycle_window_minutes: number | null;
  anchor_patterns: string[];
  custom_grok_patterns: string[];
  actionable_severities: string[] | null;
}

export interface OnboardingStatusResponse {
  status: UserStatus;
  steps: OnboardingSteps;
  aws_connection: AwsConnection | null;
  detection_config: DetectionConfig;
}

export interface AwsGuideResponse {
  platform_aws_account_id: string;
  external_id: string;
  trust_policy_template: Record<string, unknown>;
  permissions_policy_template: Record<string, unknown>;
  instructions_markdown: string;
}

export interface AwsConnectionInput {
  aws_region: string;
  log_group_name: string;
  role_arn: string;
}

export interface DetectionConfigPatch {
  error_filter_field?: string;
  error_filter_values?: string[];
  lifecycle_window_minutes?: number | null;
  anchor_patterns?: string[];
  custom_grok_patterns?: string[];
  actionable_severities?: string[] | null;
}

export interface ConnectionTestResponse {
  ok: boolean;
  message: string;
  error_code: string | null;
  verified_at: string | null;
  sample_event_count: number;
}

export interface ActivateResponse {
  status: UserStatus;
  message: string;
}

export interface DeactivateResponse {
  status: UserStatus;
}

export interface IncidentCounts {
  total: number;
  open: number;
  new_last_24h: number;
  resurgences_last_24h: number;
}

export interface MonitoringSummary {
  status: MonitoringHealthStatus;
  last_cycle_completed_at: string | null;
  last_processed_timestamp: string | null;
  last_cycle_errors_found: number | null;
  last_cycle_survivors: number | null;
  last_cycle_error: string | null;
}

export interface AwsConnectionSummary {
  connection_verified_at: string | null;
  aws_region: string | null;
  log_group_name: string | null;
}

export interface DashboardSummaryResponse {
  incidents: IncidentCounts;
  monitoring: MonitoringSummary;
  aws_connection: AwsConnectionSummary | null;
}

export interface MonitoringStatusResponse {
  user_status: UserStatus;
  poll_interval_seconds: number;
  last_cycle_started_at: string | null;
  last_cycle_completed_at: string | null;
  last_processed_timestamp: string | null;
  last_cycle_errors_found: number | null;
  last_cycle_survivors: number | null;
  last_cycle_error: string | null;
  aws_connection_ok: boolean;
}

export interface IncidentListItem {
  id: string;
  fingerprint: string;
  status: IncidentStatus;
  exception_type: string | null;
  exception_code: string | null;
  message: string | null;
  endpoint: string | null;
  occurrence_count: number;
  first_seen_at: string;
  last_seen_at: string;
  has_evidence: boolean;
  lifecycle_status: LifecycleStatus | null;
  correlation_method: CorrelationMethod | string | null;
}

export interface IncidentListResponse {
  items: IncidentListItem[];
  total: number;
  limit: number;
  offset: number;
}

export interface LifecycleEvent {
  timestamp: string;
  level: string;
  event: string | null;
  message: string | null;
  statusCode?: number | null;
  durationMs?: number | null;
  traceId?: string | null;
  spanId?: string | null;
  loggerName?: string | null;
}

export interface ExceptionDetails {
  exception_type: string | null;
  code: string | null;
  message: string | null;
  stack: string | null;
}

export interface Evidence {
  fingerprint: string;
  error_timestamp: string;
  endpoint: string | null;
  request_id: string | null;
  service?: string | null;
  traceId?: string | null;
  spanId?: string | null;
  sessionId?: string | null;
  podName?: string | null;
  containerId?: string | null;
  host?: string | null;
  env?: string | null;
  version?: string | null;
  loggerName?: string | null;
  exception: ExceptionDetails;
  lifecycle: LifecycleEvent[];
  lifecycle_status: LifecycleStatus;
  correlation_method: CorrelationMethod | string;
  correlation_confidence: CorrelationConfidence | string;
  correlation_notes: string[];
  raw_error_line: Record<string, unknown>;
  gathered_at: string;
}

export interface IncidentDetail extends IncidentListItem {
  evidence: Evidence | null;
  suspect_commit_sha: string | null;
  classification: string | null;
  pr_url: string | null;
  created_at: string;
  updated_at: string;
}

export interface OccurrenceItem {
  id: string;
  request_id: string | null;
  timestamp: string;
  raw_log_line: Record<string, unknown>;
}

export interface OccurrenceListResponse {
  items: OccurrenceItem[];
  total: number;
  limit: number;
  offset: number;
}

export interface IncidentPatchRequest {
  status: IncidentStatus;
}

export interface HealthResponse {
  status: string;
  service: string;
  db: string | null;
}

export interface IncidentListParams {
  status?: IncidentListFilter;
  since?: string;
  limit?: number;
  offset?: number;
}

export interface OccurrenceListParams {
  limit?: number;
  offset?: number;
}

import type {
  ActivateResponse,
  ApiError,
  AuthMeResponse,
  AwsConnectionInput,
  AwsGuideResponse,
  ConnectionTestResponse,
  DashboardSummaryResponse,
  DeactivateResponse,
  DetectionConfig,
  DetectionConfigPatch,
  HealthResponse,
  IncidentDetail,
  IncidentListParams,
  IncidentListResponse,
  IncidentPatchRequest,
  MonitoringStatusResponse,
  OccurrenceListParams,
  OccurrenceListResponse,
  OnboardingStatusResponse,
} from "@/types/api";

export const API_URL =
  process.env.NEXT_PUBLIC_API_URL ?? "http://localhost:8000";

export class ApiClientError extends Error {
  constructor(
    public status: number,
    public body: ApiError,
  ) {
    super(
      typeof body.detail === "string" ? body.detail : body.detail.detail,
    );
    this.name = "ApiClientError";
  }
}

async function request<T>(path: string, init: RequestInit = {}): Promise<T> {
  const res = await fetch(`${API_URL}${path}`, {
    ...init,
    credentials: "include",
    headers: {
      "Content-Type": "application/json",
      ...init.headers,
    },
  });

  if (res.status === 204) {
    return undefined as T;
  }

  const text = await res.text();
  const data = text ? JSON.parse(text) : null;

  if (!res.ok) {
    throw new ApiClientError(res.status, data ?? { detail: res.statusText });
  }

  return data as T;
}

function queryString(
  params: Record<string, string | number | undefined>,
): string {
  const q = new URLSearchParams();
  for (const [k, v] of Object.entries(params)) {
    if (v !== undefined && v !== "") q.set(k, String(v));
  }
  const s = q.toString();
  return s ? `?${s}` : "";
}

export function googleLoginUrl(): string {
  return `${API_URL}/auth/google`;
}

export const auth = {
  me: () => request<AuthMeResponse>("/auth/me"),
  logout: () => request<void>("/auth/logout", { method: "POST" }),
};

export const onboarding = {
  status: () => request<OnboardingStatusResponse>("/onboarding/status"),
  awsGuide: () => request<AwsGuideResponse>("/onboarding/aws/guide"),
  saveAws: (body: AwsConnectionInput) =>
    request<Record<string, unknown>>("/onboarding/aws", {
      method: "PUT",
      body: JSON.stringify(body),
    }),
  testConnection: () =>
    request<ConnectionTestResponse>("/onboarding/aws/test-connection", {
      method: "POST",
    }),
  getDetectionConfig: () =>
    request<DetectionConfig>("/onboarding/detection-config"),
  patchDetectionConfig: (body: DetectionConfigPatch) =>
    request<DetectionConfig>("/onboarding/detection-config", {
      method: "PATCH",
      body: JSON.stringify(body),
    }),
  activate: () =>
    request<ActivateResponse>("/onboarding/activate", { method: "POST" }),
  deactivate: () =>
    request<DeactivateResponse>("/onboarding/deactivate", { method: "POST" }),
};

export const dashboard = {
  summary: () => request<DashboardSummaryResponse>("/dashboard/summary"),
  monitoring: () => request<MonitoringStatusResponse>("/monitoring/status"),
};

export const incidents = {
  list: (params: IncidentListParams = {}) =>
    request<IncidentListResponse>(
      `/incidents${queryString({
        status: params.status,
        since: params.since,
        limit: params.limit,
        offset: params.offset,
      })}`,
    ),
  get: (id: string) => request<IncidentDetail>(`/incidents/${id}`),
  occurrences: (id: string, params: OccurrenceListParams = {}) =>
    request<OccurrenceListResponse>(
      `/incidents/${id}/occurrences${queryString({
        limit: params.limit,
        offset: params.offset,
      })}`,
    ),
  patch: (id: string, body: IncidentPatchRequest) =>
    request<IncidentListResponse["items"][0]>(`/incidents/${id}`, {
      method: "PATCH",
      body: JSON.stringify(body),
    }),
};

export const health = {
  check: () => request<HealthResponse>("/healthz"),
};

import { format, formatDistanceToNow } from "date-fns";
import type { MonitoringHealthStatus } from "@/types/api";

export function cn(...classes: (string | false | null | undefined)[]): string {
  return classes.filter(Boolean).join(" ");
}

export function formatDateTime(iso: string | null | undefined): string {
  if (!iso) return "—";
  try {
    return format(new Date(iso), "MMM d, yyyy HH:mm:ss");
  } catch {
    return iso;
  }
}

export function formatRelative(iso: string | null | undefined): string {
  if (!iso) return "—";
  try {
    return formatDistanceToNow(new Date(iso), { addSuffix: true });
  } catch {
    return iso;
  }
}

export function monitoringStatusLabel(status: MonitoringHealthStatus): string {
  const labels: Record<MonitoringHealthStatus, string> = {
    healthy: "Healthy",
    stale: "Stale",
    degraded: "Degraded",
    setup_required: "Setup required",
    pending: "Pending",
    inactive: "Inactive",
  };
  return labels[status] ?? status;
}

export function monitoringStatusClasses(
  status: MonitoringHealthStatus,
): string {
  const map: Record<MonitoringHealthStatus, string> = {
    healthy: "bg-emerald-100 text-emerald-800 ring-emerald-600/20",
    stale: "bg-amber-100 text-amber-800 ring-amber-600/20",
    degraded: "bg-red-100 text-red-800 ring-red-600/20",
    setup_required: "bg-orange-100 text-orange-800 ring-orange-600/20",
    pending: "bg-sky-100 text-sky-800 ring-sky-600/20",
    inactive: "bg-slate-100 text-slate-600 ring-slate-500/20",
  };
  return map[status] ?? "bg-slate-100 text-slate-600 ring-slate-500/20";
}

export async function copyToClipboard(text: string): Promise<boolean> {
  try {
    await navigator.clipboard.writeText(text);
    return true;
  } catch {
    return false;
  }
}

export function getErrorMessage(error: unknown): string {
  if (error instanceof Error) return error.message;
  return "Something went wrong";
}

"use client";

import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
} from "react";
import { auth } from "@/lib/api";
import type { AuthMeResponse } from "@/types/api";

interface AuthContextValue {
  user: AuthMeResponse | null;
  loading: boolean;
  refresh: () => Promise<AuthMeResponse | null>;
  logout: () => Promise<void>;
}

const AuthContext = createContext<AuthContextValue | null>(null);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<AuthMeResponse | null>(null);
  const [loading, setLoading] = useState(true);

  const refresh = useCallback(async () => {
    try {
      const me = await auth.me();
      setUser(me);
      return me;
    } catch {
      setUser(null);
      return null;
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    void refresh();
  }, [refresh]);

  const logout = useCallback(async () => {
    await auth.logout();
    setUser(null);
  }, []);

  const value = useMemo(
    () => ({ user, loading, refresh, logout }),
    [user, loading, refresh, logout],
  );

  return (
    <AuthContext.Provider value={value}>{children}</AuthContext.Provider>
  );
}

export function useAuth(): AuthContextValue {
  const ctx = useContext(AuthContext);
  if (!ctx) {
    throw new Error("useAuth must be used within AuthProvider");
  }
  return ctx;
}

"use client";

import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { useState } from "react";
import { AuthProvider } from "@/contexts/auth-context";

export function Providers({ children }: { children: React.ReactNode }) {
  const [queryClient] = useState(
    () =>
      new QueryClient({
        defaultOptions: {
          queries: {
            staleTime: 15_000,
            retry: 1,
          },
        },
      }),
  );

  return (
    <QueryClientProvider client={queryClient}>
      <AuthProvider>{children}</AuthProvider>
    </QueryClientProvider>
  );
}

"use client";

import { useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/contexts/auth-context";
import { Spinner } from "@/components/ui/spinner";

type AuthGuardMode = "guest" | "authenticated" | "active";

interface AuthGuardProps {
  mode: AuthGuardMode;
  children: React.ReactNode;
}

export function AuthGuard({ mode, children }: AuthGuardProps) {
  const { user, loading } = useAuth();
  const router = useRouter();

  useEffect(() => {
    if (loading) return;

    if (mode === "guest") {
      if (user?.status === "active") router.replace("/dashboard");
      else if (user) router.replace("/onboarding");
      return;
    }

    if (!user) {
      router.replace("/login");
      return;
    }

    if (mode === "active" && user.status !== "active") {
      router.replace("/onboarding");
    }

    if (mode === "authenticated" && user.status === "active") {
      // onboarding page uses authenticated mode; active users redirected by page
    }
  }, [user, loading, mode, router]);

  if (loading) {
    return (
      <div className="flex min-h-[50vh] items-center justify-center">
        <Spinner label="Loading session…" />
      </div>
    );
  }

  if (mode === "guest" && user) return null;
  if (mode === "authenticated" && !user) return null;
  if (mode === "active" && (!user || user.status !== "active")) return null;

  return <>{children}</>;
}

export function HomeRedirect() {
  const { user, loading } = useAuth();
  const router = useRouter();

  useEffect(() => {
    if (loading) return;
    if (!user) router.replace("/login");
    else if (user.status === "active") router.replace("/dashboard");
    else router.replace("/onboarding");
  }, [user, loading, router]);

  return (
    <div className="flex min-h-screen items-center justify-center bg-slate-50">
      <Spinner label="Redirecting…" />
    </div>
  );
}

