"use client";

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";
import { OnboardingRedirectGuard } from "@/components/auth/onboarding-guard";
import { Alert } from "@/components/ui/alert";
import { Button } from "@/components/ui/button";
import { Card, CardBody, CardHeader } from "@/components/ui/card";
import { Input, Textarea } from "@/components/ui/input";
import { Spinner } from "@/components/ui/spinner";
import { useAuth } from "@/contexts/auth-context";
import { onboarding } from "@/lib/api";
import { copyToClipboard, getErrorMessage } from "@/lib/utils";
import type { AwsConnectionInput, OnboardingSteps } from "@/types/api";

const STEPS = [
  { id: "overview", label: "Overview" },
  { id: "aws-guide", label: "AWS setup" },
  { id: "aws-connect", label: "Connect AWS" },
  { id: "detection", label: "Detection" },
  { id: "activate", label: "Activate" },
] as const;

type StepId = (typeof STEPS)[number]["id"];

function StepChecklist({ steps }: { steps: OnboardingSteps }) {
  const items = [
    { key: "aws_connection_saved", label: "AWS connection saved" },
    { key: "aws_connection_verified", label: "AWS connection verified" },
    { key: "detection_config_saved", label: "Detection config saved" },
    { key: "monitoring_active", label: "Monitoring active" },
  ] as const;

  return (
    <ul className="space-y-2">
      {items.map((item) => {
        const done = steps[item.key];
        return (
          <li key={item.key} className="flex items-center gap-2 text-sm">
            <span
              className={
                done
                  ? "flex h-5 w-5 items-center justify-center rounded-full bg-emerald-100 text-xs text-emerald-700"
                  : "flex h-5 w-5 items-center justify-center rounded-full bg-slate-100 text-xs text-slate-400"
              }
            >
              {done ? "✓" : "·"}
            </span>
            <span className={done ? "text-slate-900" : "text-slate-500"}>
              {item.label}
            </span>
          </li>
        );
      })}
    </ul>
  );
}

function CopyField({ label, value }: { label: string; value: string }) {
  const [copied, setCopied] = useState(false);

  async function handleCopy() {
    const ok = await copyToClipboard(value);
    if (ok) {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  }

  return (
    <div className="space-y-1.5">
      <div className="flex items-center justify-between gap-2">
        <label className="text-sm font-medium text-slate-700">{label}</label>
        <Button variant="ghost" size="sm" onClick={handleCopy}>
          {copied ? "Copied" : "Copy"}
        </Button>
      </div>
      <pre className="overflow-x-auto rounded-lg border border-slate-200 bg-slate-50 p-3 text-xs text-slate-800">
        {value}
      </pre>
    </div>
  );
}

export default function OnboardingPage() {
  const router = useRouter();
  const queryClient = useQueryClient();
  const { refresh } = useAuth();
  const [step, setStep] = useState<StepId>("overview");
  const [message, setMessage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const statusQuery = useQuery({
    queryKey: ["onboarding", "status"],
    queryFn: onboarding.status,
  });

  const guideQuery = useQuery({
    queryKey: ["onboarding", "aws-guide"],
    queryFn: onboarding.awsGuide,
    enabled: step === "aws-guide" || step === "aws-connect",
  });

  const aws = statusQuery.data?.aws_connection;
  const detection = statusQuery.data?.detection_config;

  const [awsForm, setAwsForm] = useState<AwsConnectionInput>({
    aws_region: "us-east-1",
    log_group_name: "",
    role_arn: "",
  });

  const [filterField, setFilterField] = useState("level");
  const [filterValues, setFilterValues] = useState("ERROR, CRITICAL");
  const [lifecycleWindow, setLifecycleWindow] = useState("");

  useEffect(() => {
    if (aws) {
      setAwsForm({
        aws_region: aws.aws_region,
        log_group_name: aws.log_group_name,
        role_arn: aws.role_arn,
      });
    }
  }, [aws]);

  useEffect(() => {
    if (detection) {
      setFilterField(detection.error_filter_field);
      setFilterValues(detection.error_filter_values.join(", "));
      setLifecycleWindow(
        detection.lifecycle_window_minutes?.toString() ?? "",
      );
    }
  }, [detection]);

  const saveAwsMutation = useMutation({
    mutationFn: onboarding.saveAws,
    onSuccess: async () => {
      setMessage("AWS settings saved.");
      setError(null);
      await queryClient.invalidateQueries({ queryKey: ["onboarding"] });
    },
    onError: (err) => setError(getErrorMessage(err)),
  });

  const testMutation = useMutation({
    mutationFn: onboarding.testConnection,
    onSuccess: async (result) => {
      if (result.ok) {
        setMessage(result.message);
        setError(null);
      } else {
        setError(result.message);
        setMessage(null);
      }
      await queryClient.invalidateQueries({ queryKey: ["onboarding"] });
    },
    onError: (err) => setError(getErrorMessage(err)),
  });

  const detectionMutation = useMutation({
    mutationFn: onboarding.patchDetectionConfig,
    onSuccess: async () => {
      setMessage("Detection config saved.");
      setError(null);
      await queryClient.invalidateQueries({ queryKey: ["onboarding"] });
    },
    onError: (err) => setError(getErrorMessage(err)),
  });

  const activateMutation = useMutation({
    mutationFn: onboarding.activate,
    onSuccess: async (result) => {
      setMessage(result.message);
      setError(null);
      await refresh();
      await queryClient.invalidateQueries();
      router.replace("/dashboard");
    },
    onError: (err) => setError(getErrorMessage(err)),
  });

  if (statusQuery.isLoading) {
    return (
      <OnboardingRedirectGuard>
        <div className="flex min-h-screen items-center justify-center">
          <Spinner label="Loading onboarding…" />
        </div>
      </OnboardingRedirectGuard>
    );
  }

  const currentStepIndex = STEPS.findIndex((s) => s.id === step);

  return (
    <OnboardingRedirectGuard>
      <div className="min-h-screen bg-slate-50 px-4 py-10">
        <div className="mx-auto max-w-3xl space-y-6">
          <div>
            <h1 className="text-2xl font-semibold text-slate-900">
              Set up Backtrace
            </h1>
            <p className="mt-1 text-sm text-slate-600">
              Connect AWS CloudWatch and configure error detection.
            </p>
          </div>

          <div className="flex flex-wrap gap-2">
            {STEPS.map((s, index) => (
              <button
                key={s.id}
                type="button"
                onClick={() => setStep(s.id)}
                className={
                  step === s.id
                    ? "rounded-full bg-indigo-600 px-3 py-1 text-xs font-medium text-white"
                    : index <= currentStepIndex
                      ? "rounded-full bg-indigo-100 px-3 py-1 text-xs font-medium text-indigo-700"
                      : "rounded-full bg-white px-3 py-1 text-xs font-medium text-slate-500 ring-1 ring-slate-200"
                }
              >
                {index + 1}. {s.label}
              </button>
            ))}
          </div>

          {message ? <Alert variant="success">{message}</Alert> : null}
          {error ? <Alert variant="error">{error}</Alert> : null}

          {step === "overview" && statusQuery.data ? (
            <Card>
              <CardHeader>
                <h2 className="font-medium text-slate-900">Progress</h2>
              </CardHeader>
              <CardBody className="space-y-4">
                <StepChecklist steps={statusQuery.data.steps} />
                <Button onClick={() => setStep("aws-guide")}>Get started</Button>
              </CardBody>
            </Card>
          ) : null}

          {step === "aws-guide" ? (
            <Card>
              <CardHeader>
                <h2 className="font-medium text-slate-900">AWS IAM setup</h2>
              </CardHeader>
              <CardBody className="space-y-4">
                {guideQuery.isLoading ? (
                  <Spinner label="Loading guide…" />
                ) : guideQuery.data ? (
                  <>
                    <CopyField
                      label="Platform AWS account ID"
                      value={guideQuery.data.platform_aws_account_id}
                    />
                    <CopyField
                      label="External ID"
                      value={guideQuery.data.external_id}
                    />
                    <CopyField
                      label="Trust policy template"
                      value={JSON.stringify(
                        guideQuery.data.trust_policy_template,
                        null,
                        2,
                      )}
                    />
                    <CopyField
                      label="Permissions policy template"
                      value={JSON.stringify(
                        guideQuery.data.permissions_policy_template,
                        null,
                        2,
                      )}
                    />
                    <div className="prose prose-sm max-w-none whitespace-pre-wrap text-sm text-slate-700">
                      {guideQuery.data.instructions_markdown}
                    </div>
                  </>
                ) : null}
                <div className="flex gap-2">
                  <Button variant="secondary" onClick={() => setStep("overview")}>
                    Back
                  </Button>
                  <Button onClick={() => setStep("aws-connect")}>
                    Continue
                  </Button>
                </div>
              </CardBody>
            </Card>
          ) : null}

          {step === "aws-connect" ? (
            <Card>
              <CardHeader>
                <h2 className="font-medium text-slate-900">AWS connection</h2>
              </CardHeader>
              <CardBody className="space-y-4">
                <Input
                  label="AWS region"
                  value={awsForm.aws_region}
                  onChange={(e) =>
                    setAwsForm((f) => ({ ...f, aws_region: e.target.value }))
                  }
                  placeholder="us-east-1"
                />
                <Input
                  label="Log group name"
                  value={awsForm.log_group_name}
                  onChange={(e) =>
                    setAwsForm((f) => ({
                      ...f,
                      log_group_name: e.target.value,
                    }))
                  }
                  placeholder="/ecs/my-service"
                  hint="Must start with /"
                />
                <Input
                  label="Role ARN"
                  value={awsForm.role_arn}
                  onChange={(e) =>
                    setAwsForm((f) => ({ ...f, role_arn: e.target.value }))
                  }
                  placeholder="arn:aws:iam::123456789012:role/BacktraceLogsReadRole"
                />
                {aws?.last_connection_error ? (
                  <Alert variant="warning" title="Last connection error">
                    {aws.last_connection_error}
                  </Alert>
                ) : null}
                <div className="flex flex-wrap gap-2">
                  <Button variant="secondary" onClick={() => setStep("aws-guide")}>
                    Back
                  </Button>
                  <Button
                    onClick={() => saveAwsMutation.mutate(awsForm)}
                    disabled={saveAwsMutation.isPending}
                  >
                    {saveAwsMutation.isPending ? "Saving…" : "Save AWS settings"}
                  </Button>
                  <Button
                    variant="secondary"
                    onClick={() => testMutation.mutate()}
                    disabled={testMutation.isPending}
                  >
                    {testMutation.isPending ? "Testing…" : "Test connection"}
                  </Button>
                  <Button
                    onClick={() => setStep("detection")}
                    disabled={!statusQuery.data?.steps.aws_connection_verified}
                  >
                    Continue
                  </Button>
                </div>
              </CardBody>
            </Card>
          ) : null}

          {step === "detection" ? (
            <Card>
              <CardHeader>
                <h2 className="font-medium text-slate-900">Detection config</h2>
              </CardHeader>
              <CardBody className="space-y-4">
                <Input
                  label="Error filter field"
                  value={filterField}
                  onChange={(e) => setFilterField(e.target.value)}
                />
                <Input
                  label="Error filter values"
                  value={filterValues}
                  onChange={(e) => setFilterValues(e.target.value)}
                  hint="Comma-separated values, e.g. ERROR, CRITICAL"
                />
                <Input
                  label="Lifecycle window (minutes)"
                  value={lifecycleWindow}
                  onChange={(e) => setLifecycleWindow(e.target.value)}
                  placeholder="Leave empty for platform default"
                  type="number"
                  min={1}
                />
                <div className="flex flex-wrap gap-2">
                  <Button variant="secondary" onClick={() => setStep("aws-connect")}>
                    Back
                  </Button>
                  <Button
                    onClick={() =>
                      detectionMutation.mutate({
                        error_filter_field: filterField,
                        error_filter_values: filterValues
                          .split(",")
                          .map((v) => v.trim())
                          .filter(Boolean),
                        lifecycle_window_minutes: lifecycleWindow
                          ? Number(lifecycleWindow)
                          : null,
                      })
                    }
                    disabled={detectionMutation.isPending}
                  >
                    {detectionMutation.isPending ? "Saving…" : "Save config"}
                  </Button>
                  <Button onClick={() => setStep("activate")}>Continue</Button>
                </div>
              </CardBody>
            </Card>
          ) : null}

          {step === "activate" ? (
            <Card>
              <CardHeader>
                <h2 className="font-medium text-slate-900">Enable monitoring</h2>
              </CardHeader>
              <CardBody className="space-y-4">
                {statusQuery.data ? (
                  <StepChecklist steps={statusQuery.data.steps} />
                ) : null}
                <p className="text-sm text-slate-600">
                  Activating starts polling CloudWatch every ~60 seconds. Make
                  sure AWS connection is verified and detection config is saved.
                </p>
                <div className="flex flex-wrap gap-2">
                  <Button variant="secondary" onClick={() => setStep("detection")}>
                    Back
                  </Button>
                  <Button
                    onClick={() => activateMutation.mutate()}
                    disabled={activateMutation.isPending}
                  >
                    {activateMutation.isPending
                      ? "Activating…"
                      : "Activate monitoring"}
                  </Button>
                </div>
              </CardBody>
            </Card>
          ) : null}
        </div>
      </div>
    </OnboardingRedirectGuard>
  );
}

