export default function DashboardPage() {
  const summaryQuery = useQuery({
    queryKey: ["dashboard", "summary"],
    queryFn: dashboard.summary,
    refetchInterval: 30_000,
  });

  const monitoringQuery = useQuery({
    queryKey: ["dashboard", "monitoring"],
    queryFn: dashboard.monitoring,
    refetchInterval: 30_000,
  });

  const incidentsQuery = useQuery({
    queryKey: ["incidents", "open", 10],
    queryFn: () => incidents.list({ status: "open", limit: 10 }),
    refetchInterval: 30_000,
  });

  const loading =
    summaryQuery.isLoading ||
    monitoringQuery.isLoading ||
    incidentsQuery.isLoading;

  const error =
    summaryQuery.error ?? monitoringQuery.error ?? incidentsQuery.error;

  return (
    <AuthGuard mode="active">
      <AppShell>
        <div className="space-y-8">
          <div className="flex flex-wrap items-start justify-between gap-4">
            <div>
              <h1 className="text-2xl font-semibold text-slate-900">Dashboard</h1>
              <p className="mt-1 text-sm text-slate-600">
                Incident overview and monitoring health.
              </p>
            </div>
            {summaryQuery.data ? (
              <Badge
                className={monitoringStatusClasses(
                  summaryQuery.data.monitoring.status,
                )}
              >
                {monitoringStatusLabel(summaryQuery.data.monitoring.status)}
              </Badge>
            ) : null}
          </div>

          {loading ? (
            <div className="flex justify-center py-16">
              <Spinner label="Loading dashboard…" />
            </div>
          ) : null}

          {error ? (
            <Alert variant="error">{String(error)}</Alert>
          ) : null}

          {summaryQuery.data ? (
            <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
              <StatCard
                label="Open incidents"
                value={summaryQuery.data.incidents.open}
              />
              <StatCard
                label="Total incidents"
                value={summaryQuery.data.incidents.total}
              />
              <StatCard
                label="New (24h)"
                value={summaryQuery.data.incidents.new_last_24h}
              />
              <StatCard
                label="Resurgences (24h)"
                value={summaryQuery.data.incidents.resurgences_last_24h}
                hint="Existing incidents with new activity"
              />
            </div>
          ) : null}

          {monitoringQuery.data ? (
            <Card>
              <CardHeader>
                <h2 className="font-medium text-slate-900">Monitoring</h2>
              </CardHeader>
              <CardBody>
                <dl className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3 text-sm">
                  <div>
                    <dt className="text-slate-500">Poll interval</dt>
                    <dd className="font-medium text-slate-900">
                      {monitoringQuery.data.poll_interval_seconds}s
                    </dd>
                  </div>
                  <div>
                    <dt className="text-slate-500">Last cycle completed</dt>
                    <dd className="font-medium text-slate-900">
                      {formatRelative(
                        monitoringQuery.data.last_cycle_completed_at,
                      )}
                    </dd>
                  </div>
                  <div>
                    <dt className="text-slate-500">Last processed</dt>
                    <dd className="font-medium text-slate-900">
                      {formatDateTime(
                        monitoringQuery.data.last_processed_timestamp,
                      )}
                    </dd>
                  </div>
                  <div>
                    <dt className="text-slate-500">Errors found (last cycle)</dt>
                    <dd className="font-medium text-slate-900">
                      {monitoringQuery.data.last_cycle_errors_found ?? "—"}
                    </dd>
                  </div>
                  <div>
                    <dt className="text-slate-500">Survivors (last cycle)</dt>
                    <dd className="font-medium text-slate-900">
                      {monitoringQuery.data.last_cycle_survivors ?? "—"}
                    </dd>
                  </div>
                  <div>
                    <dt className="text-slate-500">AWS connection</dt>
                    <dd className="font-medium text-slate-900">
                      {monitoringQuery.data.aws_connection_ok ? "OK" : "Failed"}
                    </dd>
                  </div>
                </dl>
                {monitoringQuery.data.last_cycle_error ? (
                  <Alert variant="warning" className="mt-4" title="Last cycle error">
                    {monitoringQuery.data.last_cycle_error}
                  </Alert>
                ) : null}
              </CardBody>
            </Card>
          ) : null}

          <Card>
            <CardHeader className="flex items-center justify-between">
              <h2 className="font-medium text-slate-900">Recent open incidents</h2>
              <Link
                href="/incidents"
                className="text-sm font-medium text-indigo-600 hover:text-indigo-500"
              >
                View all
              </Link>
            </CardHeader>
            <CardBody className="p-0">
              {incidentsQuery.data ? (
                <IncidentsTable items={incidentsQuery.data.items} />
              ) : null}
            </CardBody>
          </Card>
        </div>
      </AppShell>
    </AuthGuard>
  );
}

"use client";

import { useQuery } from "@tanstack/react-query";
import { useState } from "react";
import { AuthGuard } from "@/components/auth/auth-guard";
import { IncidentsTable } from "@/components/incidents/incidents-table";
import { AppShell } from "@/components/layout/app-shell";
import { Alert } from "@/components/ui/alert";
import { Button } from "@/components/ui/button";
import { Card, CardBody, CardHeader } from "@/components/ui/card";
import { Spinner } from "@/components/ui/spinner";
import { incidents } from "@/lib/api";
import type { IncidentListFilter } from "@/types/api";

const PAGE_SIZE = 20;

export default function IncidentsPage() {
  const [status, setStatus] = useState<IncidentListFilter>("open");
  const [offset, setOffset] = useState(0);

  const listQuery = useQuery({
    queryKey: ["incidents", status, offset],
    queryFn: () =>
      incidents.list({ status, limit: PAGE_SIZE, offset }),
    refetchInterval: 30_000,
  });

  function changeStatus(next: IncidentListFilter) {
    setStatus(next);
    setOffset(0);
  }

  const total = listQuery.data?.total ?? 0;
  const canPrev = offset > 0;
  const canNext = offset + PAGE_SIZE < total;

  return (
    <AuthGuard mode="active">
      <AppShell>
        <div className="space-y-6">
          <div>
            <h1 className="text-2xl font-semibold text-slate-900">Incidents</h1>
            <p className="mt-1 text-sm text-slate-600">
              Browse and manage detected errors from CloudWatch.
            </p>
          </div>

          <div className="flex flex-wrap gap-2">
            {(["open", "closed", "all"] as IncidentListFilter[]).map((s) => (
              <Button
                key={s}
                variant={status === s ? "primary" : "secondary"}
                size="sm"
                onClick={() => changeStatus(s)}
              >
                {s.charAt(0).toUpperCase() + s.slice(1)}
              </Button>
            ))}
          </div>

          <Card>
            <CardHeader>
              <p className="text-sm text-slate-500">
                {listQuery.isLoading
                  ? "Loading…"
                  : `${total} incident${total === 1 ? "" : "s"}`}
              </p>
            </CardHeader>
            <CardBody className="p-0">
              {listQuery.isLoading ? (
                <div className="flex justify-center py-16">
                  <Spinner label="Loading incidents…" />
                </div>
              ) : listQuery.error ? (
                <div className="p-6">
                  <Alert variant="error">{String(listQuery.error)}</Alert>
                </div>
              ) : listQuery.data ? (
                <IncidentsTable
                  items={listQuery.data.items}
                  emptyMessage={`No ${status === "all" ? "" : status + " "}incidents.`}
                />
              ) : null}
            </CardBody>
          </Card>

          {listQuery.data && total > PAGE_SIZE ? (
            <div className="flex items-center justify-between">
              <Button
                variant="secondary"
                size="sm"
                disabled={!canPrev}
                onClick={() => setOffset((o) => Math.max(0, o - PAGE_SIZE))}
              >
                Previous
              </Button>
              <p className="text-sm text-slate-500">
                {offset + 1}–{Math.min(offset + PAGE_SIZE, total)} of {total}
              </p>
              <Button
                variant="secondary"
                size="sm"
                disabled={!canNext}
                onClick={() => setOffset((o) => o + PAGE_SIZE)}
              >
                Next
              </Button>
            </div>
          ) : null}
        </div>
      </AppShell>
    </AuthGuard>
  );
}

"use client";

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import Link from "next/link";
import { useParams, useRouter } from "next/navigation";
import { AuthGuard } from "@/components/auth/auth-guard";
import { AppShell } from "@/components/layout/app-shell";
import { Alert } from "@/components/ui/alert";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardBody, CardHeader } from "@/components/ui/card";
import { Spinner } from "@/components/ui/spinner";
import { incidents } from "@/lib/api";
import { formatDateTime, getErrorMessage } from "@/lib/utils";
import { useState } from "react";

export default function IncidentDetailPage() {
  const params = useParams<{ id: string }>();
  const router = useRouter();
  const queryClient = useQueryClient();
  const id = params.id;
  const [occOffset, setOccOffset] = useState(0);
  const OCC_PAGE = 20;

  const incidentQuery = useQuery({
    queryKey: ["incident", id],
    queryFn: () => incidents.get(id),
    enabled: Boolean(id),
    refetchInterval: 30_000,
  });

  const occurrencesQuery = useQuery({
    queryKey: ["incident", id, "occurrences", occOffset],
    queryFn: () =>
      incidents.occurrences(id, { limit: OCC_PAGE, offset: occOffset }),
    enabled: Boolean(id),
  });

  const patchMutation = useMutation({
    mutationFn: (status: "open" | "closed") =>
      incidents.patch(id, { status }),
    onSuccess: async () => {
      await queryClient.invalidateQueries({ queryKey: ["incident", id] });
      await queryClient.invalidateQueries({ queryKey: ["incidents"] });
      await queryClient.invalidateQueries({ queryKey: ["dashboard"] });
    },
  });

  const incident = incidentQuery.data;
  const evidence = incident?.evidence;
  const occTotal = occurrencesQuery.data?.total ?? 0;

  return (
    <AuthGuard mode="active">
      <AppShell>
        <div className="space-y-6">
          <div className="flex flex-wrap items-start justify-between gap-4">
            <div>
              <Link
                href="/incidents"
                className="text-sm text-indigo-600 hover:text-indigo-500"
              >
                ← Back to incidents
              </Link>
              {incidentQuery.isLoading ? (
                <h1 className="mt-2 text-2xl font-semibold text-slate-900">
                  Loading…
                </h1>
              ) : incident ? (
                <>
                  <h1 className="mt-2 text-2xl font-semibold text-slate-900">
                    {incident.exception_type ?? "Unknown exception"}
                  </h1>
                  <p className="mt-1 text-sm text-slate-600">
                    {incident.message ?? "No message"}
                  </p>
                </>
              ) : null}
            </div>
            {incident ? (
              <div className="flex items-center gap-2">
                <Badge
                  className={
                    incident.status === "open"
                      ? "bg-amber-100 text-amber-800 ring-amber-600/20"
                      : "bg-slate-100 text-slate-600 ring-slate-500/20"
                  }
                >
                  {incident.status}
                </Badge>
                <Button
                  variant={incident.status === "open" ? "secondary" : "primary"}
                  size="sm"
                  disabled={patchMutation.isPending}
                  onClick={() =>
                    patchMutation.mutate(
                      incident.status === "open" ? "closed" : "open",
                    )
                  }
                >
                  {patchMutation.isPending
                    ? "Updating…"
                    : incident.status === "open"
                      ? "Close incident"
                      : "Reopen incident"}
                </Button>
              </div>
            ) : null}
          </div>

          {incidentQuery.isLoading ? (
            <div className="flex justify-center py-16">
              <Spinner label="Loading incident…" />
            </div>
          ) : null}

          {incidentQuery.error ? (
            <Alert variant="error">
              {getErrorMessage(incidentQuery.error)}
              {incidentQuery.error &&
              "status" in (incidentQuery.error as object) &&
              (incidentQuery.error as { status: number }).status === 404 ? (
                <div className="mt-2">
                  <Button
                    variant="secondary"
                    size="sm"
                    onClick={() => router.push("/incidents")}
                  >
                    Back to list
                  </Button>
                </div>
              ) : null}
            </Alert>
          ) : null}

          {incident ? (
            <>
              <Card>
                <CardHeader>
                  <h2 className="font-medium text-slate-900">Summary</h2>
                </CardHeader>
                <CardBody>
                  <dl className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3 text-sm">
                    <div>
                      <dt className="text-slate-500">Endpoint</dt>
                      <dd className="font-medium">{incident.endpoint ?? "—"}</dd>
                    </div>
                    <div>
                      <dt className="text-slate-500">Occurrences</dt>
                      <dd className="font-medium">{incident.occurrence_count}</dd>
                    </div>
                    <div>
                      <dt className="text-slate-500">First seen</dt>
                      <dd className="font-medium">
                        {formatDateTime(incident.first_seen_at)}
                      </dd>
                    </div>
                    <div>
                      <dt className="text-slate-500">Last seen</dt>
                      <dd className="font-medium">
                        {formatDateTime(incident.last_seen_at)}
                      </dd>
                    </div>
                    <div>
                      <dt className="text-slate-500">Lifecycle</dt>
                      <dd className="font-medium">
                        {incident.lifecycle_status ?? "—"}
                      </dd>
                    </div>
                    <div>
                      <dt className="text-slate-500">Correlation</dt>
                      <dd className="font-medium">
                        {incident.correlation_method ?? "—"}
                      </dd>
                    </div>
                  </dl>
                </CardBody>
              </Card>

              {evidence ? (
                <>
                  <Card>
                    <CardHeader>
                      <h2 className="font-medium text-slate-900">Stack trace</h2>
                    </CardHeader>
                    <CardBody>
                      <pre className="overflow-x-auto rounded-lg bg-slate-900 p-4 text-xs text-slate-100">
                        {evidence.exception.stack ??
                          evidence.exception.message ??
                          "No stack trace available"}
                      </pre>
                    </CardBody>
                  </Card>

                  <Card>
                    <CardHeader>
                      <h2 className="font-medium text-slate-900">
                        Request lifecycle
                      </h2>
                    </CardHeader>
                    <CardBody className="p-0">
                      {evidence.lifecycle.length === 0 ? (
                        <p className="px-6 py-4 text-sm text-slate-500">
                          No lifecycle events correlated.
                        </p>
                      ) : (
                        <div className="divide-y divide-slate-100">
                          {evidence.lifecycle.map((event, index) => (
                            <div
                              key={`${event.timestamp}-${index}`}
                              className="flex gap-4 px-6 py-3 text-sm"
                            >
                              <time className="shrink-0 font-mono text-xs text-slate-500">
                                {formatDateTime(event.timestamp)}
                              </time>
                              <Badge
                                className={
                                  event.level === "ERROR"
                                    ? "bg-red-100 text-red-800 ring-red-600/20"
                                    : event.level === "WARN"
                                      ? "bg-amber-100 text-amber-800 ring-amber-600/20"
                                      : "bg-slate-100 text-slate-600 ring-slate-500/20"
                                }
                              >
                                {event.level}
                              </Badge>
                              <div className="min-w-0 flex-1">
                                <p className="text-slate-900">
                                  {event.event ?? event.message ?? "—"}
                                </p>
                                {event.statusCode ? (
                                  <p className="text-xs text-slate-500">
                                    Status {event.statusCode}
                                  </p>
                                ) : null}
                              </div>
                            </div>
                          ))}
                        </div>
                      )}
                    </CardBody>
                  </Card>

                  <Card>
                    <CardHeader>
                      <h2 className="font-medium text-slate-900">Evidence metadata</h2>
                    </CardHeader>
                    <CardBody>
                      <dl className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3 text-sm">
                        <div>
                          <dt className="text-slate-500">Request ID</dt>
                          <dd className="font-mono text-xs">
                            {evidence.request_id ?? "—"}
                          </dd>
                        </div>
                        <div>
                          <dt className="text-slate-500">Service</dt>
                          <dd>{evidence.service ?? "—"}</dd>
                        </div>
                        <div>
                          <dt className="text-slate-500">Environment</dt>
                          <dd>{evidence.env ?? "—"}</dd>
                        </div>
                        <div>
                          <dt className="text-slate-500">Version</dt>
                          <dd>{evidence.version ?? "—"}</dd>
                        </div>
                        <div>
                          <dt className="text-slate-500">Confidence</dt>
                          <dd>{evidence.correlation_confidence}</dd>
                        </div>
                        <div>
                          <dt className="text-slate-500">Gathered at</dt>
                          <dd>{formatDateTime(evidence.gathered_at)}</dd>
                        </div>
                      </dl>
                    </CardBody>
                  </Card>
                </>
              ) : (
                <Alert variant="info">
                  Evidence has not been gathered yet for this incident.
                </Alert>
              )}

              <Card>
                <CardHeader>
                  <h2 className="font-medium text-slate-900">Occurrences</h2>
                </CardHeader>
                <CardBody className="space-y-4">
                  {occurrencesQuery.isLoading ? (
                    <Spinner label="Loading occurrences…" />
                  ) : occurrencesQuery.data?.items.length === 0 ? (
                    <p className="text-sm text-slate-500">No occurrences.</p>
                  ) : (
                    <div className="space-y-3">
                      {occurrencesQuery.data?.items.map((occ) => (
                        <div
                          key={occ.id}
                          className="rounded-lg border border-slate-200 bg-slate-50 p-3"
                        >
                          <div className="mb-2 flex flex-wrap items-center gap-2 text-xs text-slate-500">
                            <span>{formatDateTime(occ.timestamp)}</span>
                            {occ.request_id ? (
                              <span className="font-mono">{occ.request_id}</span>
                            ) : null}
                          </div>
                          <pre className="overflow-x-auto text-xs text-slate-800">
                            {JSON.stringify(occ.raw_log_line, null, 2)}
                          </pre>
                        </div>
                      ))}
                    </div>
                  )}
                  {occTotal > OCC_PAGE ? (
                    <div className="flex items-center justify-between pt-2">
                      <Button
                        variant="secondary"
                        size="sm"
                        disabled={occOffset === 0}
                        onClick={() =>
                          setOccOffset((o) => Math.max(0, o - OCC_PAGE))
                        }
                      >
                        Previous
                      </Button>
                      <p className="text-sm text-slate-500">
                        {occOffset + 1}–{Math.min(occOffset + OCC_PAGE, occTotal)}{" "}
                        of {occTotal}
                      </p>
                      <Button
                        variant="secondary"
                        size="sm"
                        disabled={occOffset + OCC_PAGE >= occTotal}
                        onClick={() => setOccOffset((o) => o + OCC_PAGE)}
                      >
                        Next
                      </Button>
                    </div>
                  ) : null}
                </CardBody>
              </Card>
            </>
          ) : null}

          {patchMutation.error ? (
            <Alert variant="error">{getErrorMessage(patchMutation.error)}</Alert>
          ) : null}
        </div>
      </AppShell>
    </AuthGuard>
  );
}

"use client";

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";
import { AuthGuard } from "@/components/auth/auth-guard";
import { AppShell } from "@/components/layout/app-shell";
import { Alert } from "@/components/ui/alert";
import { Button } from "@/components/ui/button";
import { Card, CardBody, CardHeader } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Spinner } from "@/components/ui/spinner";
import { useAuth } from "@/contexts/auth-context";
import { onboarding } from "@/lib/api";
import { formatDateTime, getErrorMessage } from "@/lib/utils";
import type { AwsConnectionInput } from "@/types/api";

export default function SettingsPage() {
  const router = useRouter();
  const queryClient = useQueryClient();
  const { refresh } = useAuth();
  const [message, setMessage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const statusQuery = useQuery({
    queryKey: ["onboarding", "status"],
    queryFn: onboarding.status,
  });

  const aws = statusQuery.data?.aws_connection;
  const detection = statusQuery.data?.detection_config;

  const [awsForm, setAwsForm] = useState<AwsConnectionInput>({
    aws_region: "us-east-1",
    log_group_name: "",
    role_arn: "",
  });

  const [filterField, setFilterField] = useState("level");
  const [filterValues, setFilterValues] = useState("ERROR, CRITICAL");
  const [lifecycleWindow, setLifecycleWindow] = useState("");

  useEffect(() => {
    if (aws) {
      setAwsForm({
        aws_region: aws.aws_region,
        log_group_name: aws.log_group_name,
        role_arn: aws.role_arn,
      });
    }
  }, [aws]);

  useEffect(() => {
    if (detection) {
      setFilterField(detection.error_filter_field);
      setFilterValues(detection.error_filter_values.join(", "));
      setLifecycleWindow(
        detection.lifecycle_window_minutes?.toString() ?? "",
      );
    }
  }, [detection]);

  const saveAwsMutation = useMutation({
    mutationFn: onboarding.saveAws,
    onSuccess: async () => {
      setMessage("AWS settings saved.");
      setError(null);
      await queryClient.invalidateQueries({ queryKey: ["onboarding"] });
    },
    onError: (err) => setError(getErrorMessage(err)),
  });

  const testMutation = useMutation({
    mutationFn: onboarding.testConnection,
    onSuccess: async (result) => {
      if (result.ok) {
        setMessage(result.message);
        setError(null);
      } else {
        setError(result.message);
        setMessage(null);
      }
      await queryClient.invalidateQueries({ queryKey: ["onboarding"] });
    },
    onError: (err) => setError(getErrorMessage(err)),
  });

  const detectionMutation = useMutation({
    mutationFn: onboarding.patchDetectionConfig,
    onSuccess: async () => {
      setMessage("Detection config saved.");
      setError(null);
      await queryClient.invalidateQueries({ queryKey: ["onboarding"] });
    },
    onError: (err) => setError(getErrorMessage(err)),
  });

  const deactivateMutation = useMutation({
    mutationFn: onboarding.deactivate,
    onSuccess: async () => {
      setMessage("Monitoring deactivated.");
      setError(null);
      await refresh();
      await queryClient.invalidateQueries();
      router.replace("/onboarding");
    },
    onError: (err) => setError(getErrorMessage(err)),
  });

  return (
    <AuthGuard mode="active">
      <AppShell>
        <div className="mx-auto max-w-2xl space-y-6">
          <div>
            <h1 className="text-2xl font-semibold text-slate-900">Settings</h1>
            <p className="mt-1 text-sm text-slate-600">
              Manage AWS connection, detection rules, and monitoring.
            </p>
          </div>

          {message ? <Alert variant="success">{message}</Alert> : null}
          {error ? <Alert variant="error">{error}</Alert> : null}

          {statusQuery.isLoading ? (
            <div className="flex justify-center py-16">
              <Spinner label="Loading settings…" />
            </div>
          ) : null}

          {aws ? (
            <Card>
              <CardHeader>
                <h2 className="font-medium text-slate-900">Connection status</h2>
              </CardHeader>
              <CardBody className="space-y-2 text-sm">
                <p>
                  <span className="text-slate-500">Verified at:</span>{" "}
                  {formatDateTime(aws.connection_verified_at)}
                </p>
                <p>
                  <span className="text-slate-500">Last test:</span>{" "}
                  {formatDateTime(aws.last_connection_test_at)}
                </p>
                {aws.last_connection_error ? (
                  <Alert variant="warning">{aws.last_connection_error}</Alert>
                ) : null}
              </CardBody>
            </Card>
          ) : null}

          <Card>
            <CardHeader>
              <h2 className="font-medium text-slate-900">AWS connection</h2>
            </CardHeader>
            <CardBody className="space-y-4">
              <Input
                label="AWS region"
                value={awsForm.aws_region}
                onChange={(e) =>
                  setAwsForm((f) => ({ ...f, aws_region: e.target.value }))
                }
              />
              <Input
                label="Log group name"
                value={awsForm.log_group_name}
                onChange={(e) =>
                  setAwsForm((f) => ({
                    ...f,
                    log_group_name: e.target.value,
                  }))
                }
              />
              <Input
                label="Role ARN"
                value={awsForm.role_arn}
                onChange={(e) =>
                  setAwsForm((f) => ({ ...f, role_arn: e.target.value }))
                }
              />
              <div className="flex flex-wrap gap-2">
                <Button
                  onClick={() => saveAwsMutation.mutate(awsForm)}
                  disabled={saveAwsMutation.isPending}
                >
                  {saveAwsMutation.isPending ? "Saving…" : "Save AWS settings"}
                </Button>
                <Button
                  variant="secondary"
                  onClick={() => testMutation.mutate()}
                  disabled={testMutation.isPending}
                >
                  {testMutation.isPending ? "Testing…" : "Test connection"}
                </Button>
              </div>
            </CardBody>
          </Card>

          <Card>
            <CardHeader>
              <h2 className="font-medium text-slate-900">Detection config</h2>
            </CardHeader>
            <CardBody className="space-y-4">
              <Input
                label="Error filter field"
                value={filterField}
                onChange={(e) => setFilterField(e.target.value)}
              />
              <Input
                label="Error filter values"
                value={filterValues}
                onChange={(e) => setFilterValues(e.target.value)}
                hint="Comma-separated"
              />
              <Input
                label="Lifecycle window (minutes)"
                value={lifecycleWindow}
                onChange={(e) => setLifecycleWindow(e.target.value)}
                type="number"
                min={1}
              />
              <Button
                onClick={() =>
                  detectionMutation.mutate({
                    error_filter_field: filterField,
                    error_filter_values: filterValues
                      .split(",")
                      .map((v) => v.trim())
                      .filter(Boolean),
                    lifecycle_window_minutes: lifecycleWindow
                      ? Number(lifecycleWindow)
                      : null,
                  })
                }
                disabled={detectionMutation.isPending}
              >
                {detectionMutation.isPending ? "Saving…" : "Save detection config"}
              </Button>
            </CardBody>
          </Card>

          <Card>
            <CardHeader>
              <h2 className="font-medium text-slate-900">Monitoring</h2>
            </CardHeader>
            <CardBody className="space-y-3">
              <p className="text-sm text-slate-600">
                Deactivating stops CloudWatch polling and returns your account
                to setup mode. You can re-activate from onboarding.
              </p>
              <Button
                variant="danger"
                onClick={() => deactivateMutation.mutate()}
                disabled={deactivateMutation.isPending}
              >
                {deactivateMutation.isPending
                  ? "Deactivating…"
                  : "Deactivate monitoring"}
              </Button>
            </CardBody>
          </Card>
        </div>
      </AppShell>
    </AuthGuard>
  );
}

